# Base exception for the application
class AppError(Exception):
    """Base exception for the application."""
    def __init__(self, message, code=None):
        self.message = message
        self.code = code
        super().__init__(message)

    def __str__(self):
        if self.code:
            return f"[{self.code}] {self.message}"
        return self.message

# Specific exceptions
class ValidationError(AppError):
    """Raised when input validation fails."""
    def __init__(self, field, message, value=None):
        self.field = field
        self.value = value
        super().__init__(f"{field}: {message}", code="VALIDATION_ERROR")

class NotFoundError(AppError):
    """Raised when a resource is not found."""
    def __init__(self, resource_type, resource_id):
        self.resource_type = resource_type
        self.resource_id = resource_id
        super().__init__(
            f"{resource_type} with id {resource_id} not found",
            code="NOT_FOUND"
        )

class AuthenticationError(AppError):
    """Raised when authentication fails."""
    def __init__(self, reason="Invalid credentials"):
        super().__init__(reason, code="AUTH_ERROR")

# Usage
def create_user(name, age):
    if not name or not name.strip():
        raise ValidationError("name", "cannot be empty", value=name)
    if not isinstance(age, int) or age < 0 or age > 150:
        raise ValidationError("age", "must be between 0 and 150", value=age)
    return {"name": name, "age": age}

def get_user(user_id):
    users = {1: "Alice", 2: "Bob"}
    if user_id not in users:
        raise NotFoundError("User", user_id)
    return users[user_id]

