# Full chain inspection
def full_chain(exc):
    """Walk the exception chain."""
    chain = []
    while exc is not None:
        chain.append(f"{type(exc).__name__}: {exc}")
        exc = exc.__cause__ or exc.__context__
    return chain

try:
