import os

# Example 1: Dictionary access
data = {"name": "Alice", "age": 30}

# LBYL
if "email" in data:
    email = data["email"]
else:
    email = "unknown"

# EAFP (Pythonic)
try:
    email = data["email"]
except KeyError:
    email = "unknown"

# Even better: use dict.get()
email = data.get("email", "unknown")

# Example 2: File operations
path = "/tmp/config.json"

# LBYL -- race condition: file could be deleted between check and open
if os.path.exists(path):
    with open(path) as f:  # might still fail!
        content = f.read()

# EAFP -- no race condition
try:
    with open(path) as f:
        content = f.read()
except FileNotFoundError:
    content = "{}"

# Example 3: Type conversion
user_input = "42"

# LBYL
if user_input.isdigit():
    number = int(user_input)
else:
    number = 0  # but isdigit() doesn't handle negative numbers!

# EAFP (handles all cases)
try:
    number = int(user_input)
except ValueError:
    number = 0

# Example 4: Attribute access (duck typing)
def get_length(obj):
    # LBYL -- checks type, not behavior
    if isinstance(obj, (list, str, tuple)):
        return len(obj)
    return None

    # EAFP -- checks behavior (duck typing)
def get_length_eafp(obj):
    try:
        return len(obj)
    except TypeError:
        return None

# Works with any object that has __len__
print(get_length_eafp([1, 2, 3]))  # 3
print(get_length_eafp("hello"))    # 5
print(get_length_eafp(42))         # None

# When LBYL IS appropriate: expensive operations
def process_file(path):
    # LBYL is OK here: checking is cheap, opening/reading is expensive
    if not os.path.isfile(path):
        raise FileNotFoundError(f"Not a file: {path}")
    if os.path.getsize(path) > 100_000_000:  # 100MB
        raise ValueError(f"File too large: {path}")
    # Now proceed with expensive processing
    with open(path) as f:
        return f.read()

